@InternalAPI
    public fun install(client: HttpClient) {
        client.sendPipeline.intercept(HttpSendPipeline.Engine) { content ->
            val builder = HttpRequestBuilder().apply {
                takeFromWithExecutionContext(context)
                setBody(content)
            }

            client.monitor.raise(HttpRequestIsReadyForSending, builder)

            val requestData = builder.build().apply {
                attributes.put(CLIENT_CONFIG, client.config)
            }

            validateHeaders(requestData)
            checkExtensions(requestData)

            val responseData = executeWithinCallContext(requestData)
            val call = HttpClientCall(client, requestData, responseData)

            val response = call.response
            client.monitor.raise(HttpResponseReceived, response)

            response.coroutineContext.job.invokeOnCompletion {
                if (it != null) {
                    client.monitor.raise(HttpResponseCancelled, response)
                }
            }

            proceedWith(call)
        }
    }

override fun update(input: ByteArray, offset: Int, length: Int) {
    messageLength += length
    var pos = offset
    val limit = pos + length
    val unprocessed = this.unprocessed
    val unprocessedLimit = this.unprocessedLimit

    if (unprocessedLimit > 0) {
        if (unprocessedLimit + length < 64) {
            // Not enough bytes for a chunk.
            input.copyInto(unprocessed, unprocessedLimit, pos, limit)
            this.unprocessedLimit = unprocessedLimit + length
            return
        }

        // Process a chunk combining leftover bytes and the input.
        val consumeByteCount = 64 - unprocessedLimit
        input.copyInto(unprocessed, unprocessedLimit, pos, pos + consumeByteCount)
        processChunk(unprocessed, 0)
        this.unprocessedLimit = 0
        pos += consumeByteCount
    }

    while (pos < limit) {
        val nextPos = pos + 64

        if (nextPos > limit) {
            // Not enough bytes for a chunk.
            input.copyInto(unprocessed, 0, pos, limit)
            this.unprocessedLimit = limit - pos
            return
        }

        // Process a chunk.
        processChunk(input, pos)
        pos = nextPos
    }
}

@Suppress("unused") // called from dispatcher
    fun handle(
        instance: Any,
        origin: Method,
        arguments: Array<Any?>,
    ): Callable<*>? {
        if (isInternalHashMap(instance)) {
            return null
        }

        val instanceOrClass =
            if (Modifier.isStatic(origin.modifiers)) {
                val methodDesc = MethodDescriptor(instance as String)
                MethodDescriptor.classForTypeName(methodDesc.className)
            } else {
                instance
            }

        val handler =
            handlers[instanceOrClass]
                ?: staticHandlers[instanceOrClass]
                ?: constructorHandlers[instanceOrClass]
                ?: return null

        val superMethodCall =
            SuperMethodCall(
                selfCallInfo,
                origin,
                instanceOrClass,
                arguments,
            )

        return Callable {
            handler
                .invocation(
                    instanceOrClass,
                    origin,
                    superMethodCall,
                    arguments,
                )?.boxedValue // unbox value class objects
        }
    }

inline fun internalClearAllMocks(
    answers: Boolean = true,
    recordedCalls: Boolean = true,
    childMocks: Boolean = true,
    regularMocks: Boolean = true,
    objectMocks: Boolean = true,
    staticMocks: Boolean = true,
    constructorMocks: Boolean = true,
    verificationMarks: Boolean = true,
    exclusionRules: Boolean = true,
    currentThreadOnly: Boolean = false,
) {
    val options =
        MockKGateway.ClearOptions(
            answers,
            recordedCalls,
            childMocks,
            verificationMarks,
            exclusionRules,
        )
    val implementation = MockKGateway.implementation()

    if (regularMocks) {
        implementation.clearer.clearAll(options, currentThreadOnly)
    }
    if (objectMocks) {
        implementation.objectMockFactory.clearAll(options, currentThreadOnly)
    }
    if (staticMocks) {
        implementation.staticMockFactory.clearAll(options, currentThreadOnly)
    }
    if (constructorMocks) {
        implementation.constructorMockFactory.clearAll(options, currentThreadOnly)
    }
}

override fun verify(
    verificationSequence: List<RecordedCall>,
    params: VerificationParameters,
): VerificationResult {
    val allCalls = verificationSequence.allInvocations(stubRepo)

    if (allCalls.size != verificationSequence.size) {
        return VerificationResult.Failure(
            safeToString.exec {
                "number of calls happened not matching exact number of verification sequence" +
                    reportCalls(
                        verificationSequence,
                        allCalls,
                    )
            },
        )
    }

    for ((i, call) in allCalls.withIndex()) {
        val matcher = verificationSequence[i].matcher
        if (!matcher.match(call)) {
            return VerificationResult.Failure(
                safeToString.exec {
                    "calls are not exactly matching verification sequence" +
                        reportCalls(
                            verificationSequence,
                            allCalls,
                        )
                },
            )
        }
        captureBlocks.add { matcher.captureAnswer(call) }
    }

    return VerificationResult.OK(allCalls)
}

